<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Snake Game</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            background-color: #1a1a1a;
            color: #ffffff;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            flex-direction: column;
            justify-content: center;
            align-items: center;
            min-height: 100vh;
            gap: 20px;
            padding: 20px;
        }

        h1 {
            font-size: 36px;
            margin-bottom: 10px;
            color: #00ff00;
            text-shadow: 0 0 10px rgba(0, 255, 0, 0.3);
        }

        .container {
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 20px;
        }

        #snake {
            border: 3px solid #00ff00;
            background-color: #0a0a0a;
            width: 400px;
            height: 400px;
            display: block;
            box-shadow: 0 0 20px rgba(0, 255, 0, 0.2);
        }

        .info-row {
            display: flex;
            align-items: center;
            gap: 30px;
            font-size: 20px;
            font-weight: bold;
        }

        .score-display {
            color: #00ff00;
        }

        #score {
            font-size: 28px;
            color: #00ff00;
        }

        .controls {
            display: flex;
            gap: 15px;
        }

        button {
            padding: 12px 24px;
            font-size: 16px;
            background-color: #00ff00;
            color: #000000;
            border: none;
            border-radius: 4px;
            cursor: pointer;
            font-weight: bold;
            transition: all 0.2s;
        }

        button:hover:not(:disabled) {
            background-color: #00dd00;
            box-shadow: 0 0 10px rgba(0, 255, 0, 0.5);
        }

        button:active:not(:disabled) {
            background-color: #00bb00;
        }

        button:disabled {
            background-color: #666666;
            color: #999999;
            cursor: not-allowed;
        }
    </style>
</head>
<body>
    <h1>🐍 SNAKE</h1>
    <div class="container">
        <canvas id="snake" width="400" height="400"></canvas>
        <div class="info-row">
            <div class="score-display">Score: <span id="score">0</span></div>
        </div>
        <div class="controls">
            <button id="start">Start</button>
            <button id="pause">Pause</button>
            <button id="reset">Reset</button>
        </div>
    </div>

    <script>
        const canvas = document.getElementById('snake');
        const ctx = canvas.getContext('2d');
        const scoreDisplay = document.getElementById('score');
        const startBtn = document.getElementById('start');
        const pauseBtn = document.getElementById('pause');
        const resetBtn = document.getElementById('reset');

        const GRID_WIDTH = 20;
        const GRID_HEIGHT = 20;
        const CELL_SIZE = canvas.width / GRID_WIDTH;

        let gameState = {
            snake: [],
            food: [10, 10],
            direction: 'right',
            nextDirection: 'right',
            score: 0,
            alive: true,
            running: false
        };

        function initGame() {
            gameState.snake = [
                [10, 10],
                [9, 10],
                [8, 10]
            ];
            gameState.direction = 'right';
            gameState.nextDirection = 'right';
            gameState.score = 0;
            gameState.alive = true;
            gameState.running = false;
            gameState.food = [15, 10];
            scoreDisplay.textContent = '0';
            draw();
        }

        function getDirectionVector(dir) {
            const dirs = {
                'up': [0, -1],
                'down': [0, 1],
                'left': [-1, 0],
                'right': [1, 0]
            };
            return dirs[dir];
        }

        function isOpposite(dir1, dir2) {
            const opposites = {
                'up': 'down',
                'down': 'up',
                'left': 'right',
                'right': 'left'
            };
            return opposites[dir1] === dir2;
        }

        function setDirection(dir) {
            if (!isOpposite(gameState.direction, dir)) {
                gameState.nextDirection = dir;
            }
        }

        function tick() {
            if (!gameState.alive) return;

            gameState.direction = gameState.nextDirection;

            const [dx, dy] = getDirectionVector(gameState.direction);
            const head = gameState.snake[0];
            const newHead = [head[0] + dx, head[1] + dy];

            if (newHead[0] < 0 || newHead[0] >= GRID_WIDTH ||
                newHead[1] < 0 || newHead[1] >= GRID_HEIGHT) {
                gameState.alive = false;
                gameState.running = false;
                draw();
                return;
            }

            for (let i = 0; i < gameState.snake.length; i++) {
                if (newHead[0] === gameState.snake[i][0] &&
                    newHead[1] === gameState.snake[i][1]) {
                    gameState.alive = false;
                    gameState.running = false;
                    draw();
                    return;
                }
            }

            gameState.snake.unshift(newHead);

            if (newHead[0] === gameState.food[0] && newHead[1] === gameState.food[1]) {
                gameState.score++;
                scoreDisplay.textContent = gameState.score;
                spawnFood();
            } else {
                gameState.snake.pop();
            }

            draw();
        }

        function spawnFood() {
            let x, y;
            let occupied = true;
            while (occupied) {
                x = Math.floor(Math.random() * GRID_WIDTH);
                y = Math.floor(Math.random() * GRID_HEIGHT);
                occupied = gameState.snake.some(segment =>
                    segment[0] === x && segment[1] === y
                );
            }
            gameState.food = [x, y];
        }

        function setFood(x, y) {
            gameState.food = [x, y];
            draw();
        }

        function draw() {
            ctx.fillStyle = '#0a0a0a';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            ctx.strokeStyle = '#222';
            ctx.lineWidth = 0.5;
            for (let i = 0; i <= GRID_WIDTH; i++) {
                ctx.beginPath();
                ctx.moveTo(i * CELL_SIZE, 0);
                ctx.lineTo(i * CELL_SIZE, canvas.height);
                ctx.stroke();
            }
            for (let i = 0; i <= GRID_HEIGHT; i++) {
                ctx.beginPath();
                ctx.moveTo(0, i * CELL_SIZE);
                ctx.lineTo(canvas.width, i * CELL_SIZE);
                ctx.stroke();
            }

            gameState.snake.forEach((segment, index) => {
                if (index === 0) {
                    ctx.fillStyle = '#00ff00';
                } else {
                    ctx.fillStyle = '#00cc00';
                }
                ctx.fillRect(
                    segment[0] * CELL_SIZE + 1,
                    segment[1] * CELL_SIZE + 1,
                    CELL_SIZE - 2,
                    CELL_SIZE - 2
                );
            });

            ctx.fillStyle = '#ff0000';
            ctx.fillRect(
                gameState.food[0] * CELL_SIZE + 1,
                gameState.food[1] * CELL_SIZE + 1,
                CELL_SIZE - 2,
                CELL_SIZE - 2
            );

            if (!gameState.alive) {
                ctx.fillStyle = 'rgba(0, 0, 0, 0.8)';
                ctx.fillRect(0, 0, canvas.width, canvas.height);
                ctx.fillStyle = '#ff0000';
                ctx.font = 'bold 32px Arial';
                ctx.textAlign = 'center';
                ctx.textBaseline = 'middle';
                ctx.fillText('GAME OVER', canvas.width / 2, canvas.height / 2 - 20);
                ctx.font = '20px Arial';
                ctx.fillStyle = '#ffffff';
                ctx.fillText('Score: ' + gameState.score, canvas.width / 2, canvas.height / 2 + 20);
            }
        }

        let gameLoop;

        function startGame() {
            if (!gameState.alive) {
                initGame();
            }
            gameState.running = true;
            startBtn.textContent = 'Resume';
            pauseBtn.disabled = false;
            clearInterval(gameLoop);
            gameLoop = setInterval(() => {
                tick();
            }, 100);
        }

        function pauseGame() {
            gameState.running = false;
            clearInterval(gameLoop);
            startBtn.textContent = 'Resume';
        }

        function resetGame() {
            clearInterval(gameLoop);
            initGame();
            startBtn.textContent = 'Start';
            pauseBtn.disabled = true;
        }

        startBtn.addEventListener('click', startGame);
        pauseBtn.addEventListener('click', pauseGame);
        resetBtn.addEventListener('click', resetGame);
        pauseBtn.disabled = true;

        document.addEventListener('keydown', (e) => {
            const key = e.key.toLowerCase();
            if (key === 'arrowup' || key === 'arrowdown' || key === 'arrowleft' || key === 'arrowright') {
                e.preventDefault();
                const dirs = {
                    'arrowup': 'up',
                    'arrowdown': 'down',
                    'arrowleft': 'left',
                    'arrowright': 'right'
                };
                setDirection(dirs[key]);
            }
        });

        window.game = {
            w: GRID_WIDTH,
            h: GRID_HEIGHT,
            reset: initGame,
            tick: tick,
            setDir: setDirection,
            setFood: setFood,
            snake: () => gameState.snake.map(s => [s[0], s[1]]),
            food: () => [gameState.food[0], gameState.food[1]],
            alive: () => gameState.alive,
            score: () => gameState.score
        };

        initGame();
    </script>
</body>
</html>
